crate::doc_page!(
    "wasm-bindgen",
    "/zh-Hans/docs/concepts/basic-web-technologies/wasm-bindgen",
    Content::new(vec![
        p![link!("https://github.com/rustwasm/wasm-bindgen", code("wasm-bindgen")), link!("https://rustwasm.github.io/", text("The Rust and WebAssembly Working Group")), text(".")],
        p![text("Yew uses "), code("wasm-bindgen"), text(" to interact with the browser through a number of crates:")],
        ul![li![link!("https://crates.io/crates/js-sys", code("js-sys"))], li![link!("https://crates.io/crates/wasm-bindgen", code("wasm-bindgen"))], li![link!("https://crates.io/crates/wasm-bindgen-futures", code("wasm-bindgen-futures"))], li![link!("https://crates.io/crates/web-sys", code("web-sys"))]],
        p![code("wasm-bindgen"), text(" APIs with Yew. For a more in-depth guide to "), code("wasm-bindgen"), text(" and its associated crates then check out "), link!("https://wasm-bindgen.github.io/wasm-bindgen/", text("The wasm-bindgen Guide")), text(".")],
        p![text("For documentation on the above crates check out "), link!("https://wasm-bindgen.github.io/wasm-bindgen/api/wasm_bindgen/index.html", text("wasm-bindgen docs.rs")), text(".")],
        admonition!(AdmonitionType::Tip, None, p![text("Use the "), code("wasm-bindgen"), code("wasm-bindgen"), text(".")]),
        h2![link!("https://crates.io/crates/wasm-bindgen", text("wasm-bindgen"))],
        p![code("wasm-bindgen"), text(" crate and that is the macro and some types/traits you will see pop up again and again.")],
        h3![text("#[wasm_bindgen] macro")],
        p![text("The "), code("#[wasm_bindgen]"), code("js-sys"), text(" and "), code("web-sys"), text(" crates expose "), code("wasm-bindgen"), text(" definitions for built-in JavaScript types and browser APIs.")],
        p![text("Let's go over a simple example of using the "), code("#[wasm-bindgen]"), text(" macro to import some specific flavours of the "), link!("https://developer.mozilla.org/en-US/docs/Web/API/Console/log", code("console.log")), text(" function.")],
        p![text("This example was adapted from "), link!("https://wasm-bindgen.github.io/wasm-bindgen/examples/console-log.html", text("1.2 Using console.log of The wasm-bindgen Guide")), text(".")],
        h3![text("Simulating inheritance")],
        p![code("wasm-bindgen"), text(" you can also add attributes that describe their inheritance.")],
        p![text("In Rust, this inheritance is represented using the "), link!("https://doc.rust-lang.org/std/ops/trait.Deref.html", code("Deref")), text(" and "), link!("https://doc.rust-lang.org/std/convert/trait.AsRef.html", code("AsRef")), text(" traits. An example of this might help; so say you have three types "), code("A"), text(", "), code("B"), text(", and "), code("C"), text(" where "), code("C"), text(" extends "), code("B"), text(" which in turn extends "), code("A"), text(".")],
        p![text("When importing these types the "), code("#[wasm-bindgen]"), text(" macro will implement the "), code("Deref"), text(" and "), code("AsRef"), text(" traits in the following way:")],
        ul![li![code("C"), text(" can "), code("Deref"), text(" to "), code("B")], li![code("B"), text(" can "), code("Deref"), text(" to "), code("A")], li![code("C"), text(" can be "), code("AsRef"), text(" to "), code("B")], li![text("Both "), code("C"), text(" & "), code("B"), text(" can be "), code("AsRef"), text(" to "), code("A")]],
        p![text("These implementations allow you to call a method from "), code("A"), text(" on an instance of "), code("C"), text(" and to use "), code("C"), text(" as if it was "), code("&B"), text(" or "), code("&A"), text(".")],
        p![text("It is important to note that every single type imported using "), code("#[wasm_bindgen]"), text(" has the same root type, you can think of it as the "), code("A"), text(" in the example above, this type is "), link!("https://wasm-bindgen.github.io/wasm-bindgen/api/wasm_bindgen/struct.JsValue.html", code("JsValue")), text(" which has its section below.")],
        p![link!("https://wasm-bindgen.github.io/wasm-bindgen/reference/attributes/on-js-imports/extends.html", text("extends section in The wasm-bindgen Guide"))],
        h3![link!("https://wasm-bindgen.github.io/wasm-bindgen/api/wasm_bindgen/struct.JsValue.html", text("JsValue"))],
        p![text("This is a representation of an object owned by JavaScript, this is a root catch-all type for "), code("wasm-bindgen"), text(". Because JavaScript does not have a strong type system, any type that comes from "), code("wasm-bindgen"), text(" is a "), code("JsValue"), code("JsValue"), text(". If you are working with imported functions or types that accept a "), code("JsValue"), text(", then any imported value is "), italic![text("technically")], text(" valid.")],
        p![text("Even though "), code("JsValue"), text(" may be accepted by a JS function, that function may still only "), italic![text("actually")], text(" accept certain types. Passing an incorrect "), code("JsValue"), text(" can lead to an exception which triggers a panic - so when using raw "), code("wasm-bindgen"), text(" APIs, check your JavaScript's documentation for types of inputs that will cause an exception (and a panic).")],
        p![link!("https://wasm-bindgen.github.io/wasm-bindgen/api/wasm_bindgen/struct.JsValue.html", text("JsValue documentation")), text(".")],
        h3![link!("https://wasm-bindgen.github.io/wasm-bindgen/api/wasm_bindgen/trait.JsCast.html", text("JsCast"))],
        p![code("JsCast"), code("JsCast"), text(" to jump from one type to the other. It is a nice trait to get to know when working with "), code("web-sys"), text(", "), code("wasm_bindgen"), text(", "), code("js-sys"), text(" - you will notice lots of types will implement "), code("JsCast"), text(" from those crates.")],
        p![code("JsCast"), link!("https://doc.rust-lang.org/std/option/enum.Option.html", code("Option")), text(" and "), link!("https://doc.rust-lang.org/std/result/enum.Result.html", code("Result")), text(".")],
        p![text("A common example of this in "), link!("/docs/0.21/concepts/basic-web-technologies/web-sys", code("web-sys")), text(" is when you are trying to get the target of an event. You might know what the target element is, but the "), link!("https://wasm-bindgen.github.io/wasm-bindgen/api/web_sys/struct.Event.html", code("web_sys::Event")), text(" API will always return an "), link!("https://wasm-bindgen.github.io/wasm-bindgen/api/web_sys/struct.Event.html#method.target", code("Option<web_sys::EventTarget>")), text(". You will need to cast it to the element type so you can call its methods.")],
        p![text("The "), link!("https://wasm-bindgen.github.io/wasm-bindgen/api/wasm_bindgen/trait.JsCast.html#method.dyn_ref", code("dyn_ref")), text(" method is a checked cast that returns an "), code("Option<&T>"), text(", which means the original type can be used again if the cast failed and thus returned "), code("None"), text(". The "), link!("https://wasm-bindgen.github.io/wasm-bindgen/api/wasm_bindgen/trait.JsCast.html#method.dyn_into", code("dyn_into")), text(" method will consume "), code("self"), text(", as per convention for "), code("into"), text(" methods in Rust, and the type returned is "), code("Result<T, Self>"), text(". If the casting fails, the original "), code("Self"), text(" value is returned in "), code("Err"), text(". You can try again or do something else with the original type.")],
        p![link!("https://wasm-bindgen.github.io/wasm-bindgen/api/wasm_bindgen/trait.JsCast.html", text("JsCast documentation")), text(".")],
        h3![link!("https://wasm-bindgen.github.io/wasm-bindgen/api/wasm_bindgen/closure/struct.Closure.html", text("Closure"))],
        p![text("The "), code("Closure"), code("'static"), text(" lifetime for soundness reasons.")],
        p![code("Closure"), text(" has been dropped will raise an exception.")],
        p![code("Closure"), text(" is often used when you are working with a "), code("js-sys"), text(" or "), code("web-sys"), text(" API that accepts a type "), link!("https://wasm-bindgen.github.io/wasm-bindgen/api/js_sys/struct.Function.html", code("&js_sys::Function")), text(". An example of using a "), code("Closure"), text(" in Yew can be found in the "), link!("/docs/0.21/concepts/html/events#using-closure-verbose", text("Using Closure section")), text(" on the "), link!("/docs/0.21/concepts/html/events", text("Events")), text(" page.")],
        p![link!("https://wasm-bindgen.github.io/wasm-bindgen/api/wasm_bindgen/closure/struct.Closure.html", text("Closure documentation")), text(".")],
        h2![link!("https://crates.io/crates/js-sys", text("js-sys"))],
        p![text("The "), code("js-sys")],
        p![text("This does not include any web APIs; that's what "), link!("/docs/0.21/concepts/basic-web-technologies/web-sys", code("web-sys")), text(" is for!")],
        p![link!("https://wasm-bindgen.github.io/wasm-bindgen/api/js_sys/index.html", text("js-sys documentation")), text(".")],
        h2![link!("https://crates.io/crates/wasm-bindgen-futures", text("wasm-bindgen-futures"))],
        p![text("The "), code("wasm-bindgen-futures"), text(" crate provides a bridge for working with JavaScript Promise types as a Rust "), link!("https://doc.rust-lang.org/stable/std/future/trait.Future.html", code("Future"))],
        p![text("There are three main interfaces in this crate currently:")],
        ol![li![link!("https://wasm-bindgen.github.io/wasm-bindgen/api/wasm_bindgen_futures/struct.JsFuture.html", code("JsFuture")), text(" - A type that is constructed with a "), link!("https://wasm-bindgen.github.io/wasm-bindgen/api/js_sys/struct.Promise.html", code("Promise")), text(" and can then be used as a "), code("Future<Output=Result<JsValue, JsValue>>"), text(". This Future will resolve to "), code("Ok"), text(" if the Promise is resolved and "), code("Err"), text(" if the Promise is rejected, containing the resolved or rejected value from the Promise respectively.")], li![link!("https://wasm-bindgen.github.io/wasm-bindgen/api/wasm_bindgen_futures/fn.future_to_promise.html", code("future_to_promise")), text(" - Converts a Rust "), code("Future<Output=Result<JsValue, JsValue>>"), text(" into a JavaScript "), code("Promise"), text(". The future's result will translate to either a resolved or rejected Promise in JavaScript.")], li![link!("https://wasm-bindgen.github.io/wasm-bindgen/api/wasm_bindgen_futures/fn.spawn_local.html", code("spawn_local")), text(" - Spawns a "), code("Future<Output = ()>"), text(" on the current thread. This is the best way to run a Future in Rust without sending it to JavaScript.")]],
        p![link!("https://wasm-bindgen.github.io/wasm-bindgen/api/wasm_bindgen_futures/index.html", text("wasm-bindgen-futures documentation")), text(".")],
        h3![link!("https://wasm-bindgen.github.io/wasm-bindgen/api/wasm_bindgen_futures/fn.spawn_local.html", text("spawn_local"))],
        p![code("spawn_local"), text(" is going to be the most commonly used part of the "), code("wasm-bindgen-futures"), text(" crate in Yew as this helps when using libraries that have async APIs.")],
        p![text("Yew has also added support for futures in certain APIs, most notably you can create a "), code("callback_future"), text(" which accepts an "), code("async"), text(" block - this uses "), code("spawn_local"), text(" internally.")],
        p![link!("https://wasm-bindgen.github.io/wasm-bindgen/api/wasm_bindgen_futures/fn.spawn_local.html", text("spawn_local documentation")), text(".")]
    ])
);
